# --------- ОЖДАЕМ, ЧТО ГДЕ-ТО ВЫШЕ/РЯДОМ ОПРЕДЕЛЁН DATA ---------
# DATA = [...]  # список словарей с ключами: "кто","тип","здоровье","инит","броня","точн","точн2","урон","урон2",
#                                        "иммунитет","защита","тип атаки1","тип атаки2","размер"
# ------------------------------------------------------------------

# ===================== НОРМАЛЗАЦЯ/КАНОНЗАЦЯ ====================
_ATK_CANON = {
    "weapon": "Weapon",
    "earth": "Earth",
    "fire": "Fire",
    "water": "Water",
    "poison": "Poison",
    "death": "Death",
    "mind": "Mind",
    "life": "Life",
    "air": "Air",
    "": ""
}
def _canon_attack(x: str) -> str:
    return _ATK_CANON.get((x or "").lower(), (x or ""))

def _canon_list(xs):
    return [_ATK_CANON.get((x or "").lower(), (x or "")) for x in (xs or [])]


def _unit_type(u: dict) -> str:
    # Pass unit type through unchanged; _TYPE_CANON is unused here
    val = u.get("тип", "")
    return "" if val is None else str(val)

def _stand(u: dict) -> str:
    # ближник (weapon) или большой — впереди, иначе — позади
    if (u.get("тип атаки1", "").lower() == "weapon") or bool(u.get("размер", 0)):
        return "ahead"
    return "behind"

def _armor(u: dict) -> int:
    try:
        return int(round(float(u.get("броня", 0)) * 100))
    except Exception:
        return 0

def _to_acc(v) -> int:
    try:
        return int(round(float(v) * 100))
    except Exception:
        return 0

def _get(u: dict, *keys, default=0):
    for k in keys:
        if k in u:
            return u[k]
    return default


HERO_UNIT_NAMES = frozenset(
    {
        "Рыцарь на пегасе",
        "Рейнджер людей",
        "Архимаг",
        "Архангел",
        "Герцог",
        "Советник",
        "Архидьявол",
        "Баронесса",
        "Королевский страж",
        "Инженер",
        "Хранитель знаний",
        "Жезловик гномов",
        "Рыцарь смерти",
        "Носферату",
        "Королева лич",
        "Баньши",
        "Лесной лорд",
        "Хранитель леса",
        "Дриада",
        "Мудрец",
    }
)


def _to_bool_flag(value) -> bool:
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return int(value) != 0
    return str(value or "").strip().lower() in {"1", "true", "yes", "y", "on"}


def is_hero_name(name: str) -> bool:
    return str(name or "").strip() in HERO_UNIT_NAMES


def _resolve_hero_flag(u: dict) -> bool:
    if not isinstance(u, dict):
        return False
    if "hero" in u:
        return _to_bool_flag(u.get("hero"))
    if "герой" in u:
        return _to_bool_flag(u.get("герой"))
    unit_name = str(_get(u, "кто", "name", default="") or "").strip()
    if unit_name and is_hero_name(unit_name):
        return True
    next_level_raw = _get(u, "следуровень", "next_level_exp", default=0)
    try:
        return int(round(float(next_level_raw))) > 0
    except Exception:
        return False


def _resolve_capital_value(u: dict) -> int:
    if not isinstance(u, dict):
        return 0
    capital_raw = _get(u, "столица", "capital", default=0)
    try:
        return int(round(float(capital_raw)))
    except Exception:
        return 0


def _normalize_level_value(raw_level: object, default: int = 0) -> int:
    try:
        return int(round(float(raw_level)))
    except Exception:
        return int(default)


for _entry in DATA:
    if isinstance(_entry, dict):
        _entry["hero"] = _resolve_hero_flag(_entry)
        capital_v = _resolve_capital_value(_entry)
        level_v = _normalize_level_value(
            _get(_entry, "уровень", "Level", "level", default=0),
            default=0,
        )
        if capital_v == 0 and level_v < 1:
            level_v = 1
            _entry["уровень"] = level_v
        _entry["Level"] = level_v
        _entry["capital"] = capital_v
        _entry["is_neutral_unit"] = capital_v == 0

def map_unit_to_battle(u: dict, team: str, position: int) -> dict:
    """Маппинг одного словаря из DATA -> объект боевого юнита с ключами целевого формата."""
    initv = int(_get(u, "инит", "инициатива", default=0))
    hp = int(_get(u, "здоровье", "hp", default=0))
    level_raw = _get(u, "\u0443\u0440\u043e\u0432\u0435\u043d\u044c", "Level", "level", default=0)
    capital_v = _resolve_capital_value(u)
    is_neutral_unit = capital_v == 0
    # Experience fields are used by BattleEnv to distribute post-battle XP.
    # Keep numeric values where possible and preserve special string marker "max".
    exp_kill_raw = _get(u, "\u043e\u043f\u044b\u0442 \u0443\u0431\u0438\u0439\u0441\u0442\u0432\u0430", "exp_kill", default=0)
    exp_req_raw = _get(u, "\u043d\u0443\u0436\u043d\u044b\u0439 \u043e\u043f\u044b\u0442", "exp_required", default=0)
    exp_cur_raw = _get(u, "\u0442\u0435\u043a\u0443\u0449\u0438\u0439 \u043e\u043f\u044b\u0442", "exp_current", default=0)
    next_level_raw = _get(u, "\u0441\u043b\u0435\u0434\u0443\u0440\u043e\u0432\u0435\u043d\u044c", "next_level_exp", default=0)
    turns_raw = _get(u, "\u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0435\u0442\u0441\u044f \u0432", "turns_into", default=[])

    try:
        exp_kill_v = int(round(float(exp_kill_raw)))
    except Exception:
        exp_kill_v = 0

    if isinstance(exp_req_raw, str) and exp_req_raw.strip().lower() == "max":
        exp_required_v = "max"
    else:
        try:
            exp_required_v = int(round(float(exp_req_raw)))
        except Exception:
            exp_required_v = 0

    try:
        exp_current_v = int(round(float(exp_cur_raw)))
    except Exception:
        exp_current_v = 0

    try:
        next_level_exp_v = int(round(float(next_level_raw)))
    except Exception:
        next_level_exp_v = 0

    try:
        level_v = int(round(float(level_raw)))
    except Exception:
        level_v = 0
    if is_neutral_unit and level_v < 1:
        level_v = 1

    try:
        needaunit_v = 1 if int(round(float(_get(u, "needaunit", default=0)))) > 0 else 0
    except Exception:
        needaunit_v = 0

    if isinstance(turns_raw, list):
        turns_into_v = list(turns_raw)
    elif turns_raw:
        turns_into_v = [turns_raw]
    else:
        turns_into_v = []
    return {
        "name": u.get("кто", ""),
        "initiative": initv,
        "initiative_base": initv,
        "team": team,
        "position": position,
        "stand": _stand(u),
        "unit_type": _unit_type(u),
        "Level": level_v,
        "capital": capital_v,
        "is_neutral_unit": is_neutral_unit,

        "damage": int(_get(u, "урон", "damage", default=0)),
        "damage_secondary": int(_get(u, "урон2", "damage2", default=0)),

        "health": hp,
        "max_health": hp,
        "armor": _armor(u),

        "accuracy": _to_acc(_get(u, "точн", "accuracy", default=0)),
        "accuracy_secondary": _to_acc(_get(u, "точн2", "accuracy2", default=0)),

        "immunity": _canon_list(u.get("иммунитет", [])),
        "resistance": _canon_list(u.get("защита", [])),
        "attack_type_primary": _canon_attack(u.get("тип атаки1", "")),
        "attack_type_secondary": _canon_attack(u.get("тип атаки2", "")),

        "big": bool(u.get("размер", 0)),
        "paralyzed": 0,
        "long_paralyzed": 0,
        "running_away": 0,
        "transformed": 0,
        "hero": _resolve_hero_flag(u),
        "basestats": [],
        "exp_kill": exp_kill_v,
        "exp_required": exp_required_v,
        "exp_current": exp_current_v,
        "next_level_exp": next_level_exp_v,
        "needaunit": needaunit_v,
        "turns_into": turns_into_v,
    }

# =========================== ПЛЕЙСХОЛДЕРЫ ==========================
NO_SELECTION = "— пусто —"

def default_stand_for_position(position: int) -> str:
    # 1..3 и 7..9 — передняя линия, 4..6 и 10..12 — задняя
    if position in (1, 2, 3, 7, 8, 9):
        return "ahead"
    return "behind"

def placeholder_unit(team: str, position: int) -> dict:
    return {
        "name": "пусто",
        "initiative": 0,
        "initiative_base": 0,
        "team": team,
        "position": position,
        "stand": default_stand_for_position(position),
        "unit_type": "Archer",
        "damage": 0,
        "damage_secondary": 0,
        "health": 0,
        "max_health": 0,
        "armor": 0,
        "accuracy": 0,
        "accuracy_secondary": 0,
        "immunity": [],
        "resistance": [],
        "attack_type_primary": "Weapon",
        "attack_type_secondary": "",
        "big": False,
        "paralyzed": 0,
        "long_paralyzed": 0,
        "running_away": 0,
        "transformed": 0,
        "hero": False,
        "basestats": [],
        "Level": 0,
        "needaunit": 0,
    }

# ========================= ВСПОМОГАТЕЛЬНОЕ =========================
def build_name_index(data_list):
    """Собираем индекс имя -> список юнитов (на случай совпадений имен)."""
    idx = {}
    for u in data_list:
        name = u.get("кто", "")
        idx.setdefault(name, []).append(u)
    return idx

def first_by_name(name, name_index):
    lst = name_index.get(name, [])
    return lst[0] if lst else None

# --- запись в файл 1workingbattle.py ---
BEGIN_MARK = "# === BEGIN CUSTOM UNITS (GUI) ==="
END_MARK   = "# === END CUSTOM UNITS (GUI) ==="

def _render_units_block(units_red, units_blue) -> str:
    ts = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    block = [
        "",
        BEGIN_MARK,
        f"# Generated at {ts}",
        f"UNITS_RED = {pformat(units_red, width=120, compact=False, sort_dicts=False)}",
        "",
        f"UNITS_BLUE = {pformat(units_blue, width=120, compact=False, sort_dicts=False)}",
        END_MARK,
        "",
    ]
    return "\n".join(block)

def write_units_to_file(py_path: str, units_red, units_blue) -> None:
    content = ""
    if os.path.exists(py_path):
        with open(py_path, "r", encoding="utf-8") as f:
            content = f.read()

    # вырежем предыдущий кастомный блок, если есть
    if BEGIN_MARK in content and END_MARK in content:
        content = re.sub(
            re.escape(BEGIN_MARK) + r".*?" + re.escape(END_MARK),
            BEGIN_MARK + "\n" + END_MARK,
            content,
            flags=re.DOTALL
        )

    new_block = _render_units_block(units_red, units_blue)
    if content:
        if not content.endswith("\n"):
            content += "\n"
        content += new_block
    else:
        content = new_block.lstrip("\n")

    with open(py_path, "w", encoding="utf-8") as f:
        f.write(content)


